"""
MKT Christ Commentary — 1 Corinthians chapters 1-4
Run: python3 scripts/zc-christ-1corinthians-1-4.py

Source data used:
- data/interlinear/1corinthians.json
- data/translation/draft/mediating/1corinthians.json
- data/commentary/mkt-christ/1corinthians.json (preserves existing v18, v30 of ch 1)

Key Christological classification decisions:
- 1 Cor 1-4 is primarily 'direct revelation' — Paul is making explicit Christological claims
  about the cross as God's wisdom and power; these are not types or shadows but first-order
  NT proclamation about Christ's person and saving significance
- The divine election of the lowly (1:27-29) connects to the beatitudes and prophetic
  tradition but in Paul's framing it is revelation of what God does in Christ
- Christ as foundation (3:11) is both a metaphorical claim and an eschatological one:
  the Day of the Lord will test all building on that foundation
- The 'mind of Christ' (2:16) is classified as 'direct revelation' — the Spirit mediates
  participation in Christ's own knowing of the Father
- No straight double-quote characters in value strings; typographic quotes used throughout
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

CHRIST = {
  "1": {
    "1": '<p>The theme: Paul as called apostle of Christ Jesus by God\'s will. The opening places Christ at the center of the letter\'s authority structure: Paul\'s apostleship is a commission from Christ, not a self-appointed role. Every instruction and rebuke in the letter derives its authority from this Christological ground. The NT pattern of divine calling through Christ recapitulates the OT prophet\'s commissioning: called not by human agency but by divine appointment.</p>',
    "2": '<p>The church is defined by two Christological realities: sanctified <em>en Christō Iēsou</em> (in Christ Jesus) and called to be holy people. Holiness in the OT was participation in YHWH\'s character (Lev 11:44-45); in Paul, holiness is participation in Christ\'s own status before God — the sanctification Christ accomplished is the ground of the community\'s identity as holy. The letter is addressed to all who call on the name of the Lord — the Shema-style confession now directed to Jesus Christ as Lord.</p>',
    "3": '<p>The blessing formula places Christ alongside the Father as the source of grace and peace. The standard Jewish greeting adapted by Paul identifies both God our Father and the Lord Jesus Christ as the shared origin of the community\'s blessing — a Trinitarian structure embedded in every Pauline letter-opening. The co-ordination of Father and Christ as joint source is an implicit Christological claim about Christ\'s divine status.</p>',
    "4": '<p>The grace given in Christ Jesus is the Christological ground of all thanksgiving. The gifts the Corinthians have received are not generic divine endowments but specifically located <em>en Christō Iēsou</em> (in Christ Jesus) — within the sphere of Christ\'s accomplishment. Gratitude directed toward God for gifts received in Christ creates the anti-boasting logic that will govern the entire letter.</p>',
    "5": '<p>Enriched in all speech and knowledge <em>en autō</em> (in him): the gifts of eloquence and understanding are Christ-given, not self-generated achievements. This direct address to the Corinthians\' prized capacities establishes them as Christological gifts before critiquing their misuse. Gifts given by Christ cannot be grounds for competition between Christ\'s people.</p>',
    "6": '<p>The testimony of Christ was confirmed among them — Paul\'s gospel proclamation about Christ was not his own biography but a witness to what Christ had done. The divine confirmation of this testimony (through signs and transformed lives, cf. 2:4) is Christ\'s own authentication of the message about himself. The community\'s existence is the confirmation of Christ\'s testimony.</p>',
    "7": '<p>The gifts flow from the expectation of Christ\'s revelation (<em>apokalypsin tou Kyriou Iēsou Christou</em>): the community waits for the unveiling of the Lord Jesus Christ at the Parousia. All spiritual gifts are transitional provisions for the period between resurrection and return — they point toward and will be superseded by Christ\'s full manifestation. Christological eschatology is the frame within which the letter\'s discussion of gifts (chs 12-14) must be read.</p>',
    "8": '<p>Christ will keep them firm to the end so they will be blameless on his Day. The Day of the Lord, now recast as the Day of our Lord Jesus Christ, is the eschatological horizon that gives Paul\'s ethical instructions their urgency. Blamelessness on that Day is not achieved by human effort but guaranteed by Christ\'s own faithfulness: he will sustain what he began.</p>',
    "9": '<p>The faithfulness of God is expressed through the call into <em>koinōnia</em> with his Son — fellowship, participation, sharing. This is the deepest Christological claim in the letter\'s opening: the community\'s life is not merely association with Christ but participation in him. The whole of 1 Corinthians is an argument that this participation in Christ must reshape every sphere of community life: factions, sexuality, food, worship, resurrection hope.</p>',
    "10": '<p>The appeal for unity is made through the name of the Lord Jesus Christ — that name carries the authority and identity of Christ himself as the community\'s single Lord. Division in the community is a fracturing of Christ\'s own body (v. 13: is Christ divided?). The unity Paul seeks is not merely social harmony but a Christological necessity: there is one Christ, therefore there must be one community.</p>',
    "11": '<p>The report of quarrels (<em>eris</em>) comes from Chloe\'s household. The factions represent a fundamental misunderstanding of what Christ accomplished: if different apostles are merely channels through whom one Christ operates, there is no basis for choosing between them. The quarrels reveal a misplaced Christology — treating apostolic personalities as the ultimate referent instead of Christ himself.</p>',
    "12": '<p>The party-names (I follow Paul; I follow Apollos; I follow Cephas; I follow Christ) all reveal the same error: making Christ one option among several allegiances. Even the Christ-party, if it understood itself as superior to the others, was using Christ as a faction-banner rather than recognizing him as the Lord of all the parties. The use of Christ\'s name to build a competitive faction is a misappropriation of his person.</p>',
    "13": '<p>Three rhetorical questions expose the absurdity of the factions: Is Christ divided? — No, his body is one. Was Paul crucified for you? — No, only Christ was crucified for sinners. Were you baptized into Paul\'s name? — No, baptism creates union with Christ, not with apostles. All three questions place the saving events — cross and baptism — in Christ alone, not in any apostolic figure. Christology demolishes the factional logic.</p>',
    "14": '<p>Paul\'s relief at not having baptized many in Corinth is grounded in the exclusive Christological allegiance that baptism creates. Baptism in the NT is <em>eis Christon</em> (into Christ), not into an apostle\'s sphere of influence. The factional problem is partly liturgical: baptism wrongly understood creates patron-client bonds with the baptizer rather than covenant-union with Christ.</p>',
    "15": '<p>The concern is that no one could say they were baptized into Paul\'s name — the name of baptism belongs to Christ alone. The threefold baptismal name (Matt 28:19: Father, Son, Holy Spirit) or the simple name of the Lord Jesus Christ (Acts 2:38) establishes Christ as the one into whose reality believers enter at baptism. No apostle can share that exclusive position.</p>',
    "16": '<p>The parenthetical admission about Stephanas\'s household does not undermine the point: Paul is not denying that he baptized, but that he baptized in his own name or to create personal followings. Christological allegiance through baptism is to Christ; the agent of baptism is irrelevant to the union created.</p>',
    "17": '<p>The cross must not be emptied (<em>kenōthē ho stauros</em>) by the wisdom of words: rhetorical display draws attention to the speaker and away from the saving event. The cross is the singular Christological fact; everything else serves to make it visible or obscures it. The tension between eloquent proclamation and cross-centred content runs through all Pauline preaching.</p>',
    "19": '<p>Isa 29:14 — God will destroy the wisdom of the wise — is read as prophetic anticipation of the cross. The same divine logic that judged Israel\'s trust in human wisdom now operates through the crucified Christ: God\'s wisdom-demolishing wisdom is concentrated in the foolishness of the cross. The prophetic judgment on human self-reliance finds its ultimate expression in the cross event.</p>',
    "20": '<p>The cross has made obsolete the categories of present-age wisdom: the philosopher, the scribe, the rhetor have no answer to the cross. Christ crucified is not a proposition that can be evaluated by the world\'s standards because it belongs to the coming age breaking into the present — the age whose wisdom the cross inaugurates. The cross renders the wise people of this age (<em>ho aion houtos</em>) without a valid framework.</p>',
    "21": '<p>God chose to save through the foolishness of proclamation: the proclaimed Christ-event is the vehicle of salvation that natural wisdom cannot replicate. The wisdom of God deployed in the cross is not a higher grade of the same rational process but a completely different epistemological mode — revelation through historical event and Spirit-enabled reception, not philosophical demonstration. Christology is the content of the foolish proclamation that saves.</p>',
    "22": '<p>Jews seek signs and Greeks seek wisdom: both are seeking validation in their own preferred categories. Christ crucified satisfies neither demand on its own terms — he is not the sign of military victory Jews hoped for, nor the philosophical sage Greeks admired. He is something categorically different: the wisdom and power of God in the form of a crucified criminal, legible only from within the community shaped by the Spirit.</p>',
    "23": '<p>We preach Christ crucified: Paul\'s singular content. A crucified Messiah was a contradiction in Jewish expectation (Messiah = triumphant Davidic king) and a scandal in Greek thought (the divine cannot suffer shame). The cross is precisely this offense — it refuses to be domesticated into either tradition\'s pre-existing categories. This is why Christ crucified requires new categories: the cross creates the epistemological conditions for understanding it.</p>',
    "24": '<p>Christ as the power of God and the wisdom of God: the two titles absorb what Jews and Greeks respectively sought. They were right to seek power and wisdom — they were wrong about their sources and forms. Christ satisfies both quests at the level of ultimate fulfillment: God\'s own power (not Roman imperial power) and God\'s own wisdom (not Sophistic eloquence) are both incarnated and crucified in Christ.</p>',
    "25": '<p>The foolishness of God is wiser than human wisdom; the weakness of God is stronger than human strength: the paradox is not resolved but intensified. This is not saying that the cross turns out to be secretly strong after all by human standards — it remains genuinely weak by those standards. The point is that divine categories transcend human ones: God\'s apparent foolishness and weakness exceed all human maxima. Christ crucified is not a halfway-house between wisdom and folly but an entirely different axis.</p>',
    "26": '<p>Not many wise, powerful, or noble were called: the social composition of the community is itself a Christological statement. God\'s election operates through the cross-pattern — choosing what the world despises. The same wisdom that chose the cross chose the weak and lowly as the primary recipients. The community\'s social profile is an embodied argument for the cross\'s logic.</p>',
    "27": '<p>God chose the foolish things to shame the wise, the weak things to shame the strong. This divine reversal pattern runs from the OT through the beatitudes (Matt 5:3-12) and the Magnificat (Luke 1:46-55) and finds its concentrated expression in the cross: the King of Israel dies as a criminal, the strong one is crucified in weakness. The community\'s existence as the foolish-and-weak-chosen continues the cross-pattern into the social world.</p>',
    "28": '<p>The lowly, despised, and non-existent things chosen by God to nullify things that are: the cross is God\'s act of new creation from nothing. As God created from non-being in Gen 1:1, so in the cross God creates new covenant-people from those who were nobodies. The eschatological community is the creation-from-nothing that the cross enacts — the ultimate demonstration that salvation is entirely God\'s act, not human achievement.</p>',
    "29": '<p>So that no flesh may boast before God: the anti-boasting purpose of divine election through weakness and the cross. Boasting (<em>kauchēsis</em>) in Paul is always displaced by the cross: anyone who genuinely encounters the crucified Christ has no standing to claim achievement-credit. The cross does not merely lower human pride — it eliminates the ontological ground for it.</p>',
    "31": '<p>Let the one who boasts boast in the Lord (Jer 9:24): the only legitimate boast is one directed toward God — specifically, knowing God through Christ. In the NT context, boasting in the Lord means boasting in the crucified and risen Christ, in whom all divine gifts are given. Christological doxology is the redeemed form of human pride: glory directed entirely toward the God revealed in Christ.</p>'
  },
  "2": {
    "1": '<p>Paul\'s arrival without eloquence or superior wisdom embodies the cross-pattern: the message about Christ crucified is delivered in a manner consistent with its content. A polished rhetorical performance would contradict the cross\'s logic — the medium of proclamation must be shaped by the crucified and weakened Messiah it proclaims. Apostolic self-presentation is Christologically formed.</p>',
    "2": '<p>The decision to know nothing except Jesus Christ and him crucified is a Christological focusing that governs all of Paul\'s ministry in Corinth. The entire letter is the unpacking of this single commitment: every problem Paul addresses (factions, sexual ethics, idol food, gifts, resurrection) is answered from the cross as the center. Christ crucified is not one topic among many but the interpretive key to all topics.</p>',
    "3": '<p>Weakness, fear, and trembling: Paul\'s personal manner conforms to the cross-pattern. The crucified Christ died in weakness (2 Cor 13:4); the apostle proclaims him in weakness. There is a Christological coherence between the content of the message and the condition of the messenger — both reveal God\'s power through human fragility. This is not incidental but structural: the weakness of the messenger prevents faith from resting on human charisma.</p>',
    "4": '<p>The demonstration of the Spirit and power: the validation of the crucified Christ\'s message comes not through argumentative skill but through the Spirit\'s accompanying power — healings, transformed lives, the tangible presence of the risen Christ working through the proclamation. This Spirit-power is the resurrection\'s ongoing expression: Christ risen is active in the proclamation about Christ crucified.</p>',
    "5": '<p>Faith resting on God\'s power, not human wisdom: Christological faith is necessarily faith in the one who acts, not in the persuasive force of an argument. The shift from argument-based confidence to power-based confidence is a shift from trust in human capacity to trust in the risen Christ who authenticates his own gospel through the Spirit.</p>',
    "6": '<p>The wisdom among the mature is the wisdom of God\'s plan in Christ, hidden through the ages and now revealed through the Spirit. This is not a second-tier Christianity for advanced practitioners but the full depth of what the cross means — the disclosure of God\'s eternal strategy for the salvation of the world through the apparent foolishness of the crucified Christ. Maturity in Christ means understanding the cross more deeply, not transcending it.</p>',
    "7": '<p>The mystery hidden before the ages but destined for our glory: Paul\'s <em>mystērion</em> is not a secret doctrine for insiders but God\'s hidden plan now revealed in Christ. The mystery is Christ himself (Col 1:27: the mystery is Christ in you, the hope of glory). Predestined <em>pro tōn aiōnōn</em> (before the ages): the cross was not God\'s emergency contingency plan but his eternal intention for the world\'s salvation.</p>',
    "8": '<p>The rulers of this age crucified the Lord of glory: the cross is the moment of maximum Christological revelation and maximum human misreading. Christ is the Lord of glory (<em>ho Kyrios tēs doxēs</em>) — the title applied to YHWH in Ps 24:7-10 — yet he was crucified by those who could not recognize what they were doing. The cross is simultaneously the ultimate expression of divine glory and the ultimate human rejection of divine wisdom. Had the powers known, they would not have crucified him — but their ignorance was overruled by God\'s purpose.</p>',
    "9": '<p>What eye has not seen, ear has not heard, heart has not conceived — these are the things God has prepared for those who love him. The content of this eschatological preparation is revealed in and through Christ: the resurrection, the new creation, the fullness of God\'s presence. All the unimagined realities that await believers are guaranteed by Christ\'s own resurrection as firstfruits (15:20). The quotation gestures toward the fullness that the cross opens up.</p>',
    "10": '<p>God revealed these things through his Spirit, who searches the deep things of God. The Spirit\'s role is to mediate the knowledge of Christ: what the Father knows about the Son, the Spirit discloses to believers. The deep things of God (<em>ta bathe tou Theou</em>) are the Christological mysteries that the Spirit alone can make known — the meaning of the cross, the identity of the crucified Lord, the eschatological glory that awaits.</p>',
    "11": '<p>No one knows the things of God except the Spirit of God: the epistemological principle that grounds Christological knowledge in Spirit-disclosure. To know Christ truly — to understand why the cross is wisdom and not foolishness — requires the Spirit who knows the Father\'s purposes from the inside. The cross is not self-evidently wise; it requires the Spirit\'s illuminating work to be seen as God\'s power and wisdom.</p>',
    "12": '<p>We received the Spirit from God so that we might know the things graciously given us by God: the Spirit mediates the knowledge of Christ\'s gifts. The things given by God (<em>ta hypo tou Theou charisthenta</em>) are specifically the Christological gifts: righteousness, sanctification, redemption (1:30). The Spirit\'s work is to make the community aware of what it already possesses in Christ.</p>',
    "13": '<p>Paul speaks in Spirit-taught words rather than human-wisdom words: the form of apostolic proclamation is Christologically and pneumatically shaped. Expressing spiritual things in spiritual words means that the vocabulary and categories of the gospel are given by the Spirit, not constructed by human rhetoric. The language of the cross is taught by the crucified one\'s own Spirit.</p>',
    "14": '<p>The unspiritual person cannot receive the things of the Spirit: the epistemological barrier is not intellectual but relational. Without the Spirit who knows Christ from the inside, the cross appears as foolishness. The spiritual discernment required to understand Christ crucified as God\'s wisdom is itself a gift — it cannot be achieved by natural intelligence, only received from the Spirit of the crucified.</p>',
    "15": '<p>The spiritual person judges all things: those who have the Spirit participate in Christ\'s own discernment — his capacity to evaluate reality from God\'s perspective. The pneumatic person is not subject to external human judgment because they operate from a reference point (the crucified and risen Christ known through the Spirit) that the purely natural evaluator cannot access. This is not elitism but a description of what Spirit-mediated Christological knowledge actually enables.</p>',
    "16": '<p>We have the mind of Christ: the climactic Christological claim of the chapter. The Spirit who searched the deep things of God (v. 10) grants believers participation in Christ\'s own perspective — his way of evaluating wisdom, power, and glory through the lens of the cross. The mind of Christ is not a private spirituality but the community\'s shared epistemic orientation: reading all things — factions, food, gifts, death — through the cross and resurrection.</p>'
  },
  "3": {
    "1": '<p>Paul could not address them as pneumatics (spiritual people) but as fleshly, as infants in Christ. The growth-metaphor is Christological: Christian maturity means increasing conformity to Christ crucified — deepening understanding of the cross as God\'s wisdom, increasing willingness to bear weakness as Christ bore it. The Corinthians\' factional behavior shows they have not advanced in this Christological formation.</p>',
    "2": '<p>Milk, not solid food: elementary Christological teaching vs. the deeper dimensions of the cross and resurrection. The progression from milk to solid food in Paul\'s context is not from the cross to something beyond it but from surface acquaintance with the cross to full understanding of its cosmic scope — its victory over the powers, its creation of a new humanity, its eschatological implications in the resurrection of 15:12-58.</p>',
    "3": '<p>Jealousy and quarreling as evidence of fleshly (<em>sarkikos</em>) existence: conformity to the pattern of this age rather than to the crucified Christ. The cross is the model for the community\'s social ethics: Christ did not compete for status or assert privilege but gave himself. A community shaped by the cross cannot be characterized by competitive factionalism without contradicting its own foundation.</p>',
    "4": '<p>Following Paul or following Apollos: the factional allegiances reveal a this-age, uncrucified social logic. To say <em>I follow Paul</em> is to evaluate Paul as a patron-figure rather than as a servant of the crucified Christ. The test of genuine Christological formation is whether the community\'s social life reflects the servant-pattern of Christ or the status-competition pattern of the surrounding culture.</p>',
    "5": '<p>Paul and Apollos are servants through whom you came to believe, as the Lord assigned. The word <em>diakonoi</em> (servants/ministers) intentionally echoes Christ\'s own self-description: the Son of Man came not to be served but to serve (Mark 10:45). Apostolic ministry is Christ-shaped servanthood, not patron-client leadership. The Lord who assigns their roles is the criterion by which they are evaluated.</p>',
    "6": '<p>Paul planted, Apollos watered, God gave the growth: the community belongs to no apostle but to God, who accomplishes growth through Christ. The founding and watering of the community are ultimately Christ\'s acts through human instruments — the same Christ who is the foundation (v. 11), the community\'s life-source, and the one in whom all things are held together (Col 1:17).</p>',
    "7": '<p>Neither the planter nor the waterer is anything — only God who gives the growth. This radical relativization of apostolic importance is grounded in Christology: if Christ is the foundation and the Spirit is the life-source, then apostles are merely conduits. The community\'s ultimate loyalty is to Christ, whose growth-giving activity makes all apostolic work possible.</p>',
    "8": '<p>Each will be rewarded according to their own labor: the eschatological evaluation of apostolic work. The reward is given by Christ on the Day of the Lord (v. 13: the Day will reveal it), not by popular acclaim. The quality of community-building work is measured by its conformity to the cross-shaped pattern of Christ\'s own ministry — servant-orientation, not prestige-seeking.</p>',
    "9": '<p>You are God\'s field, God\'s building: the community belongs to God, not to any apostolic patron. The building metaphor (oikodomē) will develop into the temple metaphor (naos, v. 16), where the community is the dwelling-place of God\'s Spirit — constituted by Christ\'s redemption and the Spirit\'s indwelling. The Christological foundation makes the building God\'s property.</p>',
    "10": '<p>By the grace God gave me, Paul laid a foundation as a wise builder: Paul\'s apostolic work is grace-given, not self-achieved. The foundation he laid is Christ himself (v. 11) — not a body of doctrine about Christ, but Christ in person as the community\'s ground. The grace enabling Paul\'s ministry is the same grace that makes Christ the foundation: both are undeserved divine acts.</p>',
    "11": '<p>No one can lay a foundation other than the one already laid, which is Jesus Christ: the most direct Christological claim in ch. 3. Christ himself is the foundation — not a teaching about Christ, not an apostolic tradition, but the person of Jesus Christ as the community\'s ontological ground. This is the decisive refutation of apostolic factionalism: the foundation is not Paul, not Apollos, not Peter, but Christ alone.</p>',
    "12": '<p>Building on this foundation with gold, silver, stones, wood, hay, straw: different qualities of community-building work. The quality is measured by how closely it conforms to the Christ-shaped pattern of the foundation — servant-oriented, cross-bearing, Spirit-dependent. The eschatological fire will reveal which community-building work was genuinely Christological and which was sub-Christological performance.</p>',
    "13": '<p>The Day will reveal the quality of each work by fire: the Day of the Lord (Christ\'s return) is the eschatological quality-test. This Christological judgment is not about personal salvation but apostolic stewardship: how faithfully did each builder build the community on the Christ-foundation? The fire of Christ\'s judgment purifies and reveals what is lasting (genuine Christological formation) from what is temporary (mere social performance).</p>',
    "14": '<p>If what was built survives, the builder will receive a reward: eschatological commendation from Christ for faithful Christological community-building. The reward (<em>misthos</em>) is given by the one who is both foundation and judge — Christ himself. The apostle\'s ultimate accountability is not to the community that evaluates their rhetoric but to Christ who evaluates the quality of their building work.</p>',
    "15": '<p>If burned up, the builder will be saved but as through fire — suffering loss of reward but not of salvation. Christological security (being saved) is not conditional on apostolic performance quality, but reward is. This establishes Christ as the guarantor of the community\'s ultimate standing even when the building work has been substandard — salvation rests on the foundation, not the superstructure.</p>',
    "16": '<p>You are the temple of God and the Spirit of God dwells in you: the community as Christ\'s new temple. In the OT, YHWH\'s presence dwelt in the Tabernacle and Temple; in the NT, that presence has relocated to the community constituted by Christ\'s redemption. The Spirit who dwells in the community is the Spirit of Christ (Rom 8:9) — the community is made a temple by Christ\'s atoning work and the Spirit\'s indwelling.</p>',
    "17": '<p>Destroying God\'s temple brings divine destruction: the holiness of the community is Christ-grounded and therefore non-negotiable. The factional behavior, the immorality, the competitive wisdom-displays are all forms of temple-destruction — attacks on the community that Christ purchased and the Spirit indwells. The severity of the warning reflects the seriousness of the Christological violation: you are destroying what Christ died to create.</p>',
    "18": '<p>Do not deceive yourselves — if you think yourself wise by this age\'s standards, become a fool in order to become wise. The cross demands a foolishness-crossing from this-age wisdom to the wisdom of God. The entry into genuine wisdom is through the apparent foolishness of the cross: acknowledging that Christ crucified is wiser than all human systems. Becoming a fool means accepting the cross\'s judgment on human wisdom-projects.</p>',
    "19": '<p>The wisdom of this world is foolishness in God\'s sight: the cross-reversal applies to epistemology as much as to social status. God catches the wise in their craftiness (Job 5:13): the very sophistication that enables them to construct elaborate wisdom-systems becomes the trap. Christ crucified exposes the pretensions of all wisdom that does not reckon with the cross.</p>',
    "20": '<p>The Lord knows that the thoughts of the wise are futile (Ps 94:11): divine omniscience renders all human wisdom-projects ultimately empty before the cross. The contrast is between human scheming (<em>dialogismous</em>) and God\'s actual purposes revealed in Christ. The cross is the place where human wisdom-projects go to die and God\'s purposes are vindicated.</p>',
    "21": '<p>No more boasting about human leaders — all things are yours: the anti-boasting conclusion leads to an extraordinary counter-claim. Because Christ is the foundation and the Lord of all apostles, those who belong to Christ possess all apostles, not just one faction\'s favorite. The Christological inversion: client-mentality (I follow Paul) impoverishes; Christ-belonging enriches beyond measure.</p>',
    "22": '<p>Paul, Apollos, Cephas, the world, life, death, present, future — all yours: the eschatological scope of Christological belonging. In Christ, believers already own the entire created order — not in the sense of present possession but in the sense of ultimate inheritance (Rom 8:17). The present age and all its powers, including death itself, belong to those who belong to Christ (Rom 8:38-39). The factions competing over apostles are like children fighting over crumbs when they already own the bakery.</p>',
    "23": '<p>You are of Christ, and Christ is of God: the relational chain that grounds everything. The community\'s belonging to Christ is the same in kind (though different in nature) as Christ\'s belonging to the Father. As the Son relates to the Father in eternal generation and love, so believers relate to Christ in grace-union and participation. This Trinitarian chain is the deepest anti-faction argument: you belong to the one who belongs to God — your identity is secured at that level, not at the level of apostolic patronage.</p>'
  },
  "4": {
    "1": '<p>Servants of Christ and stewards of God\'s mysteries: apostolic identity is Christologically defined by downward roles, not upward status. <em>Hypēretai Christou</em> (servants of Christ): the apostles are functionaries of Christ, not independent agents. <em>Oikonomoi mystēriōn Theou</em> (stewards of God\'s mysteries): the mysteries are the Christological plan disclosed in the gospel — apostles are entrusted with the announcement of what God has done in Christ, not the inventors of it.</p>',
    "2": '<p>Faithfulness is the steward\'s requirement: apostolic accountability is to Christ, not to audience approval. The faithful steward delivers the master\'s goods intact and correctly. Applied to apostolic ministry: the gospel of Christ crucified must be delivered without the distortion of rhetorical self-display, cultural accommodation, or factional loyalty. Faithfulness to Christ is the single criterion.</p>',
    "3": '<p>Human evaluation is a very small thing; even self-evaluation is unreliable: it is the Lord who judges. The eschatological displacement of human judgment to Christ as the ultimate evaluator removes the power of the Corinthian assessment of Paul. Christ\'s judgment on the Last Day is the only verdict that counts — and that verdict will be made by the one who was himself crucified as a criminal and raised as Lord.</p>',
    "4": '<p>A clear conscience does not guarantee divine acquittal: the ultimate standard is Christ\'s evaluation, not the conscience\'s verdict. The conscience can be uninformed or self-deceived; Christ as judge has perfect knowledge of both actions and motives. Paul\'s detachment from human evaluation is grounded in his acceptance of Christ as the only evaluation that matters.</p>',
    "5": '<p>Judge nothing before the appointed time — wait until the Lord comes. The Lord\'s coming (<em>elthē ho Kyrios</em>) is the Parousia of Christ when hidden things will be exposed. The eschatological judgment is not punitive terror but revelatory clarity: every person\'s work will be fully seen and fairly evaluated by the one who himself knows what it is to suffer unjust human judgment. Praise will come from God — the ultimate honor-award belongs to Christ to give, not to the Corinthians to bestow.</p>',
    "6": '<p>Paul applied these things to himself and Apollos for the Corinthians\' benefit: the apostolic examples are pedagogical models of Christological humility. The principle <em>me hyper ha gegraptai</em> (nothing beyond what is written) grounds apostolic authority in Scripture — neither Paul nor Apollos has authority beyond what the Christ-centered Scripture establishes. Puffed-up faction-building is ruled out by the Christological ground of all apostolic ministry.</p>',
    "7": '<p>What do you have that you did not receive? The rhetorical question dismantles every form of Corinthian self-congratulation. Gifts of wisdom, eloquence, spiritual experience — all received from God through Christ. This is the anti-boasting argument in its simplest form: the cross defines Christian identity as entirely gift-received, never self-achieved. Those who have Christ\'s Spirit receive everything; there is nothing to boast in.</p>',
    "8": '<p>Already satisfied, already rich, already reigning — without us! Paul\'s irony exposes the Corinthians\' over-realized eschatology. The kingdom has not yet fully come; Christ has not yet returned; the resurrection has not yet transformed the body. To act as if all eschatological blessings are already in hand is to skip the cross-shaped present — the suffering-with-Christ that precedes glorification-with-Christ (Rom 8:17). The apostles\' ongoing suffering (vv. 9-13) is the present Christological reality, not the triumphalism the Corinthians have appropriated prematurely.</p>',
    "9": '<p>God has put the apostles on display as those condemned to death — a spectacle for the whole cosmos. The apostolic peristasis is not incidental suffering but Christological conformity: as Christ was put on display at the cross as a condemned criminal, so the apostles are put on display as weak, dishonored, and condemned. The cross-pattern is not limited to one moment in history but continues in the apostolic body until the Parousia.</p>',
    "10": '<p>We are fools for Christ (<em>mōroi dia Christon</em>): the fool-vocabulary from 1:18-25 is now applied to Paul\'s own apostolic experience. The wisdom of the cross is manifested in the community of the cross-shaped: those who have accepted the foolishness of the crucified Christ as their framework have become fools by the standards of the present age. The contrast with the Corinthians\' self-perception — wise, strong, honored — exposes their cross-avoidance.</p>',
    "11": '<p>Hunger, thirst, nakedness, brutality, homelessness: the peristasis catalogue as embodied Christology. Christ himself experienced poverty (2 Cor 8:9), homelessness (Matt 8:20), and rejection by his own people (John 1:11). Apostolic hardship is not random suffering but participation in the cross-pattern of the Lord who gave himself. Paul\'s suffering is not evidence against Christ\'s power but evidence of conformity to Christ\'s cruciform existence.</p>',
    "12": '<p>Working with our own hands; when cursed, we bless; when persecuted, we endure; when slandered, we answer kindly: the behavioral pattern of the crucified Christ in apostolic existence. Christ blessed those who cursed him (Luke 23:34), endured those who persecuted him (Heb 12:3), and answered his accusers with truth rather than retaliation (Matt 26:63-64). The apostle\'s cross-shaped responses are not mere ethical choices but Christological conformity — Paul is showing what it looks like to live the cross.</p>',
    "13": '<p>We have become the scum of the earth, the garbage of the world: the nadir of social status as the Christological place of apostolic existence. Christ was treated as a criminal and hanged outside the city (Heb 13:12-13) — the ultimate social rejection. Paul\'s position as <em>peripsēma</em> (scum/refuse) is the apostolic continuation of the cross\'s social shame. Those who follow the crucified Christ must be willing to share his social location.</p>',
    "14": '<p>I write this not to shame you but to warn you as my dear children: Paul\'s fatherly relationship with the Corinthian community is itself grounded in the gospel. His concern is not self-promotion but their formation in Christ. The cross-shaped apostle calls for cross-shaped community life — the warning is pastoral, not punitive, from one who bears the cross\'s marks (cf. Gal 6:17).</p>',
    "15": '<p>You may have many guardians in Christ but not many fathers — I fathered you in Christ through the gospel. Paul\'s unique founding relationship with the Corinthian community is a spiritual paternity through Christ: the gospel that brought them to life in Christ is the same gospel Paul preached (<em>en Christō Iēsou dia tou euaggeliou egennēsa</em>). The life they have in Christ flows through the apostolic proclamation of Christ.</p>',
    "16": '<p>Become imitators of me: not self-aggrandizement but Christological pedagogy. The call to imitate Paul is grounded in Paul\'s own imitation of Christ (1 Cor 11:1: be imitators of me as I am of Christ). The chain of imitation — community imitates apostle, apostle imitates Christ — is the Christological transmission mechanism for cross-shaped living. The community learns cruciformity by watching it embodied in apostolic existence.</p>',
    "17": '<p>Timothy as faithful representative in the Lord: the chain of Christological transmission extends through co-workers. Timothy will remind them of Paul\'s ways in Christ — the cross-shaped pattern is not location-specific but universal (as I teach everywhere in every church). The Christological pattern of weak, cross-bearing apostolic ministry is the same curriculum for all communities.</p>',
    "18": '<p>Some have become arrogant as if Paul were not coming: the arrogance is a form of cross-avoidance. The puffed-up faction-leaders have used Paul\'s absence to assert their own status — exactly the patron-seeking, status-climbing behavior that the cross rules out. The arrogance is ultimately a refusal of the cross\'s verdict on human self-promotion.</p>',
    "19": '<p>Paul will come and find out not the talk of the arrogant ones but their power: the cross-criterion applied to ministry evaluation. Talk (<em>logos</em>) without Spirit-power is the Sophistic mode the cross has rendered obsolete. Paul will evaluate the Corinthian leaders by the same standard Christ applied to him — not rhetorical performance but Spirit-enabled transformation. The Lord willing: the eschatological qualification acknowledges that Christ is Lord over all apostolic plans.</p>',
    "20": '<p>The kingdom of God is not a matter of talk but of power: the eschatological kingdom that Christ inaugurated is demonstrated by Spirit-power, not rhetorical display. This is the Christological summary of the entire argument of chs 1-4: the crucified Christ is God\'s power (1:24), not human eloquence. The kingdom he established and will consummate is present and visible in Spirit-enabled transformation of lives, not in Sophistic wisdom-performances.</p>',
    "21": '<p>Shall I come with a rod of discipline or in love and a spirit of gentleness? The two modes of apostolic presence both reflect aspects of Christ: the rod of the father who disciplines (Heb 12:6-7; the Lord disciplines those he loves) and the gentleness of the one who is meek and humble in heart (Matt 11:29). The Corinthians\' response to this letter will determine which Christological mode of apostolic presence they receive.</p>'
  }
}

def main():
    existing = load_comm('mkt-christ', '1corinthians')
    merge_comm(existing, CHRIST)
    save_comm('mkt-christ', '1corinthians', existing)
    for ch in ['1', '2', '3', '4']:
        count = len(existing.get(ch, {}))
        print(f'  ch{ch}: {count} entries')

if __name__ == '__main__':
    main()
